function solve(n, edges, k) {
    class DSU {
        constructor(n) {
            this.parent = Array(n).fill(0);
            this.rank = Array(n).fill(0);
            for (let i = 0; i < n; i++) {
                this.parent[i] = i;
            }
        }

        find(x) {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }

        union(x, y) {
            const rootX = this.find(x);
            const rootY = this.find(y);
            if (rootX === rootY) return false;
            if (this.rank[rootX] < this.rank[rootY]) {
                this.parent[rootX] = rootY;
            } else {
                this.parent[rootY] = rootX;
                if (this.rank[rootX] === this.rank[rootY]) {
                    this.rank[rootX]++;
                }
            }
            return true;
        }

        countComponents() {
            const roots = new Set();
            for (let i = 0; i < this.parent.length; i++) {
                roots.add(this.find(i));
            }
            return roots.size;
        }
    }

    if (k >= n) {
        return 0;
    }

    edges.sort((a, b) => a[2] - b[2]);

    let low = 0;
    let high = edges.length - 1;
    let answer = edges[edges.length - 1][2];

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const X = edges[mid][2];
        const dsu = new DSU(n);
        for (let i = 0; i <= mid; i++) {
            const [u, v, w] = edges[i];
            dsu.union(u, v);
        }
        const components = dsu.countComponents();
        if (components <= k) {
            answer = X;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}

