class DSU(val size: Int) {
    private val parent: Array<Int>
    private val rank: Array<Int>

    init {
        parent = Array(size) { it }
        rank = Array(size) { 0 }
    }

    fun find(x: Int): Int {
        if (parent[x] != x) {
            parent[x] = find(parent[x])
        }
        return parent[x]
    }

    fun union(x: Int, y: Int): Boolean {
        val rootX = find(x)
        val rootY = find(y)
        if (rootX == rootY) return false
        if (rank[rootX] < rank[rootY]) {
            parent[rootX] = rootY
        } else {
            parent[rootY] = rootX
            if (rank[rootX] == rank[rootY]) {
                rank[rootX]++
            }
        }
        return true
    }

    fun countComponents(): Int {
        val roots = HashSet<Int>()
        for (i in 0 until size) {
            roots.add(find(i))
        }
        return roots.size
    }
}

fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
    if (k >= n) return 0

    val sortedEdges = edges.sortedWith(compareBy { it[2] })

    var low = 0L
    var high = edges.size - 1L
    var answer = sortedEdges[high][2]

    while (low <= high) {
        val mid = (low + high) / 2
        val X = sortedEdges[mid][2]

        val dsu = DSU(n.toInt())
        for (i in 0..mid) {
            val u = sortedEdges[i][0].toInt()
            val v = sortedEdges[i][1].toInt()
            dsu.union(u, v)
        }

        val components = dsu.countComponents()
        if (components <= k) {
            answer = X
            high = mid - 1
        } else {
            low = mid + 1
        }
    }

    return answer
}
