            rank[i] = 0L
        }
    }

    fun find(x: Long): Long {
        if (parent[x.toInt()] != x) {
            parent[x.toInt()] = find(parent[x.toInt()])
        }
        return parent[x.toInt()]
    }

    fun union(x: Long, y: Long): Boolean {
        val rootX = find(x)
        val rootY = find(y)
        if (rootX == rootY) return false
        if (rank[rootX.toInt()] < rank[rootY.toInt()]) {
            parent[rootX.toInt()] = rootY
        } else {
            parent[rootY.toInt()] = rootX
            if (rank[rootX.toInt()] == rank[rootY.toInt()]) {
                rank[rootX.toInt()]++
            }
        }
        return true
    }

    fun countComponents(): Int {
        val roots = mutableSetOf<Long>()
        for (i in 0 until n.toInt()) {
            roots.add(find(i.toLong()))
        }
        return roots.size
    }
