                if (rank[rootX] == rank[rootY]) {
                    rank[rootX]++
                }
            }
            return true
        }

        fun countComponents(): Int {
            val roots = mutableSetOf<Int>()
            for (i in 0 until n) {
                roots.add(find(i))
            }
            return roots.size
        }
