class DSU(val n: Int) {
    private val parent: Array<Int>
    private val rank: Array<Int>

    init {
        parent = Array(n) { it }
        rank = Array(n) { 0 }
    }

    fun find(x: Int): Int {
        if (parent[x] != x) {
            parent[x] = find(parent[x])
        }
        return parent[x]
    }

    fun union(x: Int, y: Int): Boolean {
        val rootX = find(x)
        val rootY = find(y)
        if (rootX == rootY) return false
        if (rank[rootX] < rank[rootY]) {
            parent[rootX] = rootY
        } else {
            parent[rootY] = rootX
            if (rank[rootX] == rank[rootY]) {
                rank[rootX]++
            }
        }
        return true
    }

    fun countComponents(): Int {
        val roots = HashSet<Int>()
        for (i in 0 until n) {
            roots.add(find(i))
        }
        return roots.size
    }
}

fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
    if (k >= n) return 0L

    edges.sortBy { it[2] }

    var low = 0L
